            col = cell_ref[0]  # A, B, C, etc.

            # Get value
            if cell.find('ns:v', ns) is not None:
                value = cell.find('ns:v', ns).text
            elif cell.find('ns:is/ns:t', ns) is not None:
                value = cell.find('ns:is/ns:t', ns).text
            else:
                value = None

            row_data[col] = value

        if row_data:
            income_data.append(row_data)
# Display the data
print("Income data:")
for row in income_data:
    print(row)
